import React, { createContext, useState, useContext } from 'react';

const BookingContext = createContext(null);

export const useBookings = () => {
  const context = useContext(BookingContext);
  if (!context) {
    throw new Error('useBookings must be used within a BookingProvider');
  }
  return context;
};

export const BookingProvider = ({ children }) => {
  // Store bookings: { id, userId, userName, carId, carName, carImage, startDate, endDate, totalPrice, status, remarks, createdAt }
  const [bookings, setBookings] = useState(() => {
    const stored = localStorage.getItem('bookings');
    return stored ? JSON.parse(stored) : [];
  });

  // Store returns: { id, bookingId, userId, carName, carImage, returnDate, rating, userRemarks, hasDamage, paymentStatus, status, adminRemarks, createdAt }
  const [returns, setReturns] = useState(() => {
    const stored = localStorage.getItem('returns');
    return stored ? JSON.parse(stored) : [];
  });

  const addBooking = (bookingData) => {
    const newBooking = {
      ...bookingData,
      id: Date.now().toString(),
      status: 'Pending',
      remarks: '',
      createdAt: new Date().toISOString()
    };
    const newBookings = [...bookings, newBooking];
    setBookings(newBookings);
    localStorage.setItem('bookings', JSON.stringify(newBookings));
    return newBooking;
  };

  const getBookings = () => {
    return bookings;
  };

  const getUserBookings = (userId) => {
    return bookings.filter(b => b.userId === userId);
  };

  // Get bookings that are approved and can be returned (end date has passed or user wants to return early)
  const getApprovedBookingsForReturn = (userId) => {
    return bookings.filter(b => 
      b.userId === userId && 
      (b.status === 'Approved' || b.status === 'Completed')
    );
  };

  const updateBookingStatus = (bookingId, status, remarks) => {
    const newBookings = bookings.map(b => {
      if (b.id === bookingId) {
        return { ...b, status, remarks, updatedAt: new Date().toISOString() };
      }
      return b;
    });
    setBookings(newBookings);
    localStorage.setItem('bookings', JSON.stringify(newBookings));
  };

  const getBookingById = (bookingId) => {
    return bookings.find(b => b.id === bookingId);
  };

  const deleteBooking = (bookingId) => {
    const newBookings = bookings.filter(b => b.id !== bookingId);
    setBookings(newBookings);
    localStorage.setItem('bookings', JSON.stringify(newBookings));
  };

  // Return functions
  const submitReturn = (returnData) => {
    const newReturn = {
      ...returnData,
      id: Date.now().toString(),
      status: 'Pending',
      adminRemarks: '',
      createdAt: new Date().toISOString()
    };
    const newReturns = [...returns, newReturn];
    setReturns(newReturns);
    localStorage.setItem('returns', JSON.stringify(newReturns));
    
    // Update booking status to "Returning"
    updateBookingStatus(returnData.bookingId, 'Returning', 'Return submitted');
    
    return newReturn;
  };

  const getUserReturns = (userId) => {
    return returns.filter(r => r.userId === userId);
  };

  const getAllReturns = () => {
    return returns;
  };

  const getReturnById = (returnId) => {
    return returns.find(r => r.id === returnId);
  };

  const updateReturnStatus = (returnId, status, adminRemarks) => {
    const newReturns = returns.map(r => {
      if (r.id === returnId) {
        return { ...r, status, adminRemarks, updatedAt: new Date().toISOString() };
      }
      return r;
    });
    setReturns(newReturns);
    localStorage.setItem('returns', JSON.stringify(newReturns));
    
    // Update booking status based on return approval
    const returnItem = returns.find(r => r.id === returnId);
    if (returnItem) {
      if (status === 'Approved') {
        updateBookingStatus(returnItem.bookingId, 'Returned', adminRemarks || 'Return approved - No damage');
      } else if (status === 'Rejected') {
        updateBookingStatus(returnItem.bookingId, 'Return Rejected', adminRemarks || 'Return rejected - Please resolve issues');
      }
    }
  };

  const value = {
    bookings,
    returns,
    addBooking,
    getBookings,
    getUserBookings,
    getApprovedBookingsForReturn,
    updateBookingStatus,
    getBookingById,
    deleteBooking,
    submitReturn,
    getUserReturns,
    getAllReturns,
    getReturnById,
    updateReturnStatus
  };

  return (
    <BookingContext.Provider value={value}>
      {children}
    </BookingContext.Provider>
  );
};

export default BookingContext;
